const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const newConfig = body.config || {};
const userEmail = body.userEmail || 'inconnu';
const userRole = body.userRole || 'inconnu';
const userId = body.userId || null;
const ipAddress = body.ipAddress || '';
const userAgent = body.userAgent || '';

if (!tenantId || !automationId) {
  return [{ json: { success: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, newConfig, userEmail, userRole, userId, ipAddress, userAgent, valid: true } }];

const current = $input.first().json;
const data = $('02. Valider').first().json;
const oldConfig = current.config || {};
const newConfig = data.newConfig;

// Detecter les champs modifies
const changes = [];
const allKeys = new Set([...Object.keys(oldConfig), ...Object.keys(newConfig)]);
for (const key of allKeys) {
  const oldVal = JSON.stringify(oldConfig[key] ?? null);
  const newVal = JSON.stringify(newConfig[key] ?? null);
  if (oldVal !== newVal) {
    changes.push({ champ: key, ancien: oldConfig[key] ?? null, nouveau: newConfig[key] ?? null });
  }
}

return [{ json: {
  purchaseId: current.id,
  automationNom: current.nom,
  tenantId: data.tenantId,
  automationId: data.automationId,
  oldConfig,
  newConfig,
  changes,
  userEmail: data.userEmail,
  userRole: data.userRole,
  userId: data.userId,
  ipAddress: data.ipAddress,
  userAgent: data.userAgent,
  hasChanges: changes.length > 0
} }];

// Inserer un log pour CHAQUE champ modifie
const data = $('04. Calculer differences').first().json;
const changes = data.changes || [];
const logs = [];

if (changes.length === 0) {
  // Meme si pas de changement, loguer l'acces
  logs.push({
    purchaseId: data.purchaseId,
    tenantId: data.tenantId,
    action: 'access',
    champ: null,
    ancien: null,
    nouveau: null
  });
} else {
  for (const c of changes) {
    logs.push({
      purchaseId: data.purchaseId,
      tenantId: data.tenantId,
      action: 'update',
      champ: c.champ,
      ancien: JSON.stringify(c.ancien),
      nouveau: JSON.stringify(c.nouveau)
    });
  }
}

return [{ json: { ...data, logs } }];

const data = $('04. Calculer differences').first().json;

return [{ json: {
  success: true,
  data: {
    message: data.hasChanges ? `Configuration mise a jour (${data.changes.length} champ(s) modifie(s)). L'administrateur a ete notifie.` : 'Aucune modification detectee.',
    changes: data.changes,
    hasChanges: data.hasChanges
  }
} }];
